代码中如何将图片水印居中

要将图片水印居中，请将以下行更改为：

```csharp
float x = (pageWidth - imageWidth) / 2;
float y = (pageHeight - imageHeight) / 2;
```

这将使水印图片在页面的水平和垂直方向上居中对齐。调整好的代码如下：

```csharp
static void AddImageWatermark(string inputFilePath, string outputFilePath, string watermarkImagePath)
{
    string tempFilePath = Path.GetTempFileName();
    using (PdfReader pdfReader = new PdfReader(inputFilePath))
    using (PdfWriter pdfWriter = new PdfWriter(outputFilePath))
    using (PdfDocument pdfDocument = new PdfDocument(pdfReader, pdfWriter))
    using (FileStream watermarkImageStream = File.OpenRead(watermarkImagePath))
    {
        Image watermarkImage = Image.FromStream(watermarkImageStream);
        byte[] watermarkBytes;
        using (MemoryStream ms = new MemoryStream())
        {
            using (BinaryWriter bw = new BinaryWriter(ms))
            {
                watermarkImage.Save(ms, ImageFormat.Jpeg);
                watermarkBytes = ms.ToArray();
            }
        }
        for (int i = 1; i <= pdfDocument.GetNumberOfPages(); i++)
        {
            PdfPage pdfPage = pdfDocument.GetPage(i);
            float pageWidth = pdfPage.GetPageSize().GetWidth();
            float pageHeight = pdfPage.GetPageSize().GetHeight();

            PdfCanvas pdfCanvas = new PdfCanvas(pdfPage);
            PdfExtGState extGState = new PdfExtGState();
            extGState.SetBlendMode(PdfExtGState.BM_NORMAL);
            extGState.SetFillOpacity(0.5f);
            pdfCanvas.SetExtGState(extGState);

            float imageWidth = watermarkImage.Width;
            float imageHeight = watermarkImage.Height;
            float x = (pageWidth - imageWidth) / 2;
            float y = (pageHeight - imageHeight) / 2;

            ImageData imageData = ImageDataFactory.Create(watermarkBytes, true);
            iText.Kernel.Pdf.Xobject.PdfImageXObject xobject = new iText.Kernel.Pdf.Xobject.PdfImageXObject(imageData, null);
            pdfCanvas.AddXObject(xobject, x, y, imageWidth, false);

            pdfCanvas.Release();
        }
    }
}
```

这样修改后，水印图片将在每个页面上居中显示。
